/* Element selector */
p { color: navy; }

/* Class selector */
.highlight { background: yellow; }

/* ID selector */
#header { font-size: 24px; }

/* Universal selector */
* { margin: 0; padding: 0; }

/* Group selector */
h1, h2, h3 { font-family: sans-serif; }

/* Descendant selector: section এর ভেতরের সব p */
section p { color: gray; }

/* Child selector: শুধু সরাসরি সন্তান */
ul > li { list-style: none; }

/* Adjacent sibling: ঠিক পরের ভাইবোন */
h2 + p { font-weight: bold; }
